INSERT INTO emigro_programs (id, slug, destination_iso2, program_type, title_en, title_ru, summary_en, summary_ru) VALUES
  ('b0000000-0000-4000-8000-000000000025', 'portugal-student-visa-d4', 'PT', 'STUDY', 'Portugal D4 Student Visa', 'Португалия — студенческая виза D4', 'National D4 visa for enrollment at a Portuguese school or university; proof of means and accommodation.', 'Национальная виза D4 при зачислении в португальский вуз или школу; подтверждение средств и жилья.'),
